package com.veetu.vadagai.user;import com.veetu.vadagai.common.ApiResponse;import lombok.RequiredArgsConstructor;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/v1/users") @RequiredArgsConstructor public class UserController{private final UserRepository users;private final CurrentUserService current;record Me(UUID id,String email,String fullName,String mobile,Set<Role> roles){}@GetMapping("/me") ApiResponse<Me> me(){var u=current.get();return ApiResponse.ok("Profile",new Me(u.getId(),u.getEmail(),u.getFullName(),u.getMobile(),u.getRoles()));}@GetMapping @PreAuthorize("hasRole('ADMIN')") ApiResponse<List<Me>> list(){return ApiResponse.ok("Users",users.findAll().stream().map(u->new Me(u.getId(),u.getEmail(),u.getFullName(),u.getMobile(),u.getRoles())).toList());}}
